/*
 * SNMP Client Implementation using net-snmp library
 * Demonstrates GET, SET, GETNEXT, GETBULK operations
 * Compatible with SNMPv1, v2c, and v3
 * 
 * Compile: gcc -o snmp_client snmp_client.c -lsnmp -lm
 */

#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <net-snmp/net-snmp-config.h>
#include <net-snmp/net-snmp-includes.h>

/* Common OID Definitions */
#define OID_SYS_DESCR ".1.3.6.1.2.1.1.1.0"
#define OID_SYS_UPTIME ".1.3.6.1.2.1.1.3.0"
#define OID_SYS_CONTACT ".1.3.6.1.2.1.1.4.0"
#define OID_SYS_LOCATION ".1.3.6.1.2.1.1.6.0"
#define OID_IF_NUMBER ".1.3.6.1.2.1.2.1.0"
#define OID_IF_ENTRY ".1.3.6.1.2.1.2.2.1"

/* Structure to hold SNMP session configuration */
typedef struct {
 char *target_ip;
 char *community;
 int version; /* SNMP_VERSION_1, SNMP_VERSION_2c, SNMP_VERSION_3 */
 int port;
} snmp_config_t;

/* Initialize and configure SNMP session */
struct snmp_session *init_snmp_session(snmp_config_t *config) {
 struct snmp_session session;
 struct snmp_session *sess_handle;

 /* Initialize SNMP library */
 init_snmp("snmpapp");

 /* Setup session parameters */
 snmp_sess_init(&session);
 session.version = config->version;
 session.peername = config->target_ip;
 session.community = (u_char *)config->community;
 session.community_len = strlen(config->community);
 session.remote_port = config->port;

 /* Set timeout and retries */
 session.timeout = 2000000; /* 2 seconds */
 session.retries = 3;

 /* Open the session */
 sess_handle = snmp_open(&session);

 if (!sess_handle) {
 snmp_error(&session, NULL, NULL, &session.s_errstr);
 fprintf(stderr, "Failed to open SNMP session: %s\n", session.s_errstr);
 return NULL;
 }

 return sess_handle;
}

/* Perform SNMP GET request - retrieve single MIB object value */
netsnmp_variable_list *snmp_get_request(struct snmp_session *sess_handle, 
 const char *oid_str) {
 struct snmp_pdu *pdu;
 struct snmp_pdu *response;
 netsnmp_variable_list *vars;
 int status;

 /* Create GET request PDU */
 pdu = snmp_pdu_create(SNMP_MSG_GET);

 /* Add OID to the request */
 read_objid(oid_str, pdu->variables->name, &pdu->variables->name_length);

 /* Send the request and get response */
 status = snmp_synch_response(sess_handle, pdu, &response);

 /* Process response */
 if (status == STAT_SUCCESS && response->errstat == SNMP_ERR_NOERROR) {
 return response->variables;
 } else {
 if (status == STAT_SUCCESS) {
 fprintf(stderr, "Error in response: %s\n", 
 snmp_errstring(response->errstat));
 } else if (status == STAT_TIMEOUT) {
 fprintf(stderr, "Timeout: No response from device\n");
 } else {
 fprintf(stderr, "SNMP error: %d\n", status);
 }
 return NULL;
 }
}

/* Perform SNMP GETNEXT request - traverse MIB tree sequentially */
void snmp_getnext_traversal(struct snmp_session *sess_handle, const char *oid_str) {
 struct snmp_pdu *pdu;
 struct snmp_pdu *response;
 netsnmp_variable_list *vars;
 int status;
 oid name[MAX_OID_LEN];
 size_t name_length = MAX_OID_LEN;
 int count = 0;

 /* Initialize OID from string */
 read_objid(oid_str, name, &name_length);

 printf("\n--- GETNEXT Traversal ---\n");

 /* Continue until end of MIB or 10 entries */
 while (count < 10) {
 pdu = snmp_pdu_create(SNMP_MSG_GETNEXT);
 snmp_add_null_var(pdu, name, name_length);

 status = snmp_synch_response(sess_handle, pdu, &response);

 if (status == STAT_SUCCESS && response->errstat == SNMP_ERR_NOERROR) {
 vars = response->variables;

 /* Print OID and value */
 char oid_print[MAX_OID_LEN];
 snprint_objid(oid_print, MAX_OID_LEN, vars->name, vars->name_length);

 char value_print[512];
 snprint_value(value_print, sizeof(value_print), vars->name, 
 vars->name_length, &vars->val);

 printf("%s = %s\n", oid_print, value_print);

 /* Update OID for next iteration */
 name_length = vars->name_length;
 memcpy(name, vars->name, sizeof(oid) * name_length);

 snmp_free_pdu(response);
 count++;
 } else {
 break;
 }
 }
}

/* Perform SNMP GETBULK request - efficient bulk data retrieval */
void snmp_getbulk_request(struct snmp_session *sess_handle, 
 const char *oid_str, int non_repeaters, 
 int max_repetitions) {
 struct snmp_pdu *pdu;
 struct snmp_pdu *response;
 netsnmp_variable_list *vars;
 int status;

 /* Create GETBULK request */
 pdu = snmp_pdu_create(SNMP_MSG_GETBULK);
 pdu->non_repeaters = non_repeaters;
 pdu->max_repetitions = max_repetitions;

 /* Add OID to request */
 {
 oid name[MAX_OID_LEN];
 size_t name_length = MAX_OID_LEN;
 read_objid(oid_str, name, &name_length);
 snmp_add_null_var(pdu, name, name_length);
 }

 /* Send request */
 status = snmp_synch_response(sess_handle, pdu, &response);

 printf("\n--- GETBULK Response ---\n");

 if (status == STAT_SUCCESS && response->errstat == SNMP_ERR_NOERROR) {
 /* Process all returned varbinds */
 for (vars = response->variables; vars; vars = vars->next_variable) {
 char oid_print[MAX_OID_LEN];
 char value_print[512];

 snprint_objid(oid_print, MAX_OID_LEN, vars->name, vars->name_length);
 snprint_value(value_print, sizeof(value_print), vars->name,
 vars->name_length, &vars->val);

 printf("%s = %s\n", oid_print, value_print);
 }
 } else {
 fprintf(stderr, "GETBULK failed: ");
 if (status == STAT_SUCCESS) {
 fprintf(stderr, "%s\n", snmp_errstring(response->errstat));
 } else {
 fprintf(stderr, "Status: %d\n", status);
 }
 }

 if (response) snmp_free_pdu(response);
}

/* Perform SNMP SET request - modify MIB object value */
int snmp_set_request(struct snmp_session *sess_handle, const char *oid_str,
 const char *value, int type) {
 struct snmp_pdu *pdu;
 struct snmp_pdu *response;
 netsnmp_variable_list *vars;
 int status;

 /* Create SET request PDU */
 pdu = snmp_pdu_create(SNMP_MSG_SET);

 /* Setup OID and value */
 {
 oid name[MAX_OID_LEN];
 size_t name_length = MAX_OID_LEN;
 struct variable_list var;

 read_objid(oid_str, name, &name_length);

 /* Initialize variable structure */
 memset(&var, 0, sizeof(var));
 var.name = name;
 var.name_length = name_length;

 /* Set value based on type */
 var.val.type = type;
 var.val.val.string = (u_char *)strdup(value);
 var.val_len = strlen(value);

 snmp_clone_var(&var, pdu->variables);
 }

 /* Send SET request */
 status = snmp_synch_response(sess_handle, pdu, &response);

 if (status == STAT_SUCCESS && response->errstat == SNMP_ERR_NOERROR) {
 printf("Successfully set %s = %s\n", oid_str, value);
 snmp_free_pdu(response);
 return 1;
 } else {
 fprintf(stderr, "SET failed: ");
 if (response) {
 fprintf(stderr, "%s\n", snmp_errstring(response->errstat));
 snmp_free_pdu(response);
 }
 return 0;
 }
}

/* Main function demonstrating SNMP operations */
int main(int argc, char *argv[]) {
 snmp_config_t config;
 struct snmp_session *sess_handle;
 netsnmp_variable_list *result;

 /* Configuration - modify for your environment */
 config.target_ip = "127.0.0.1";
 config.community = "public";
 config.version = SNMP_VERSION_2c; /* Use v2c */
 config.port = 161;

 printf("SNMP Client Demo - CSE\n");
 printf("Target: %s\n", config.target_ip);

 /* Initialize SNMP session */
 sess_handle = init_snmp_session(&config);
 if (!sess_handle) {
 fprintf(stderr, "Failed to initialize SNMP session\n");
 return 1;
 }

 /* Demo 1: GET request */
 printf("\n=== GET Request Demo ===\n");
 result = snmp_get_request(sess_handle, OID_SYS_DESCR);
 if (result) {
 char buf[512];
 snprint_value(buf, sizeof(buf), result->name, result->name_length, &result->val);
 printf("System Description: %s\n", buf);
 }

 /* Demo 2: GET uptime */
 result = snmp_get_request(sess_handle, OID_SYS_UPTIME);
 if (result) {
 char buf[512];
 snprint_value(buf, sizeof(buf), result->name, result->name_length, &result->val);
 printf("System Uptime: %s\n", buf);
 }

 /* Demo 3: GETNEXT traversal */
 snmp_getnext_traversal(sess_handle, OID_IF_ENTRY);

 /* Demo 4: GETBULK for interface table */
 snmp_getbulk_request(sess_handle, OID_IF_ENTRY, 0, 5);

 /* Demo 5: SET request (uncomment to test with write access) */
 /* 
 config.community = "private"; // Write community
 sess_handle = init_snmp_session(&config);
 snmp_set_request(sess_handle, OID_SYS_CONTACT, "admin@company.com", 
 ASN_OCTET_STR);
 */

 /* Cleanup */
 snmp_close(sess_handle);
 snmp_shutdown("snmpapp");

 printf("\nSNMP Demo Complete\n");
 return 0;
}
